const fields = foundry.applications.fields;


let unsorted = [];
for (let status in CONFIG.MGT2.STATUS_EFFECTS) {
    if (CONFIG.MGT2.STATUS_EFFECTS[status].locked) {
        continue;
    }
    const statusEffect = CONFIG.statusEffects.find(e => e.id === status);
    if (statusEffect) {
        unsorted.push({
            status: status,
            effect: statusEffect,
            label: game.i18n.localize(statusEffect.name)
        });
    }
}
let sorted = unsorted.sort((a, b) => {
    if (a.label < b.label) {
        return -1;
    } else if (a.label > b.label) {
        return 1;
    }
    return 0;
});

let statusOptions = [
  { label:"-", value: "" }
];
for (let status of sorted) {
    statusOptions.push({
      label: status.label,
      value: status.status
    });
}



const statusInput = fields.createSelectInput({
  name: "status",
  options: statusOptions,
  value: "surprised"
});

const content = `
  <p>Select a status to apply to all selected actors</p>
  ${statusInput.outerHTML}
`;


const data = await foundry.applications.api.DialogV2.input({
  window: { title: "Set Status" },
  content: content,
  ok: {
    label: "Set Status"
  }
});

    const status = data.status;
    console.log(status);
    const selected = canvas.tokens.controlled;

    for (let token of selected) {
      let actor = token.document.actor;
      let type = token.document.actor.type;
      if (["traveller", "npc"].includes(type)) {
        actor.addStatusEffect(status);
      }
    }
